   103→async function getAIReply(
   104→  userText: string,
   105→  campaignId: string | undefined,
   106→  history: ConversationMessage[]
   107→): Promise<string> {
   108→  // Fetch campaign data
   109→  let campaign: any = null;
   110→  if (campaignId) {
   111→    campaign = await storage.getCampaign(campaignId);
   112→  }
   113→  if (!campaign) {
   114→    campaign = await storage.getAnyCampaign();
   115→  }
