   117→  // Build campaignData object for generateAIResponse
   118→  const campaignData: CampaignData = campaign
   119→    ? {
   120→        name:               campaign.name,
   121→        goal:               campaign.goal,
   122→        additionalContext:  campaign.additionalContext || "",
   123→        ai_generated_script: campaign.ai_generated_script || campaign.script || "",
   124→        knowledge_base: [
   125→          ...(campaign.knowledgeBaseTexts || []),
   126→          ...(campaign.knowledgeBaseFiles || [])
   127→            .map((f: any) => f.extractedText)
   128→            .filter(Boolean),
