   189→// ─── Unified WebSocket setup (noServer routing) ───────────────────────────────
   190→//
   191→// Why noServer: the ws library's path-based filtering calls socket.destroy() on
   192→// any upgrade it doesn't own, so a second WebSocketServer on the same httpServer
   193→// would never receive its upgrade events.  Instead we create both servers with
   194→// noServer:true and route upgrades ourselves — unrecognised paths are left alone
   195→// so Vite HMR and other protocols can still handle them.
   196→
   197→/**
   198→ * Attach all WebSocket servers to the existing HTTP server.
   199→ *
   200→ * Paths:
   201→ *   /stream        — text + MP3 audio, for web clients and debugging
   202→ *   /exotel-stream — μ-law 8 kHz bidirectional voicebot stream for Exotel
   203→ *                    optional query param: ?campaignId=<id>
   204→ */
   205→export function setupWebSocketServer(httpServer: Server): void {
   206→  // /stream — text + MP3 debug path
   207→  const streamWss = new WebSocketServer({ noServer: true });
   208→  streamWss.on("connection", (ws, req) => {
   209→    const clientIp = req.socket.remoteAddress ?? "unknown";
   210→    log(`[/stream] Client connected [${clientIp}]  total=${streamWss.clients.size}`, "ws");
   211→    attachStreamHandlers(streamWss, ws, clientIp);
   212→  });
   213→
   214→  // /exotel-stream — Exotel voicebot path
   215→  const exotelWss = new WebSocketServer({ noServer: true });
   216→  exotelWss.on("connection", (ws, req) => {
   217→    const clientIp = req.socket.remoteAddress ?? "unknown";
   218→    let campaignId: string | undefined;
   219→    try {
   220→      const url  = new URL(req.url ?? "", `ws://${req.headers.host}`);
   221→      campaignId = url.searchParams.get("campaignId") ?? undefined;
   222→    } catch { /* ignore */ }
   223→
   224→    log(`[/exotel-stream] Connection from [${clientIp}] campaignId=${campaignId ?? "none"}  total=${exotelWss.clients.size}`, "ws");
   225→
   226→    // ── V2 Router ──────────────────────────────────────────────────────────────
   227→    //
   228→    // When USE_VOICE_ENGINE_V2 is true (default), we inspect the Exotel `start`
   229→    // event to resolve the callSid/phone, look up a registered V2 session, and
   230→    // route the socket to Voice Engine V2's TransportGateway if one is found
   231→    // AND its MediaSession is ready.
   232→    //
   233→    // In all other cases (no V2 session, MediaSession not yet wired, parse
   234→    // failure, or USE_VOICE_ENGINE_V2=false) we fall back transparently to
   235→    // handleExotelStream() (V1) — call behaviour is completely unchanged.
   236→    //
   237→    // Rollback: set USE_VOICE_ENGINE_V2 = false to bypass this block entirely.
   238→
   239→    if (!USE_VOICE_ENGINE_V2) {
   240→      log(`[V2 ROUTER] USE_VOICE_ENGINE_V2=false — routing directly to V1`, "ws");
   241→      handleExotelStream(ws, campaignId);
   242→      return;
   243→    }
   244→
   245→    log(`[V2 ROUTER] Awaiting Exotel 'start' event to resolve session`, "ws");
   246→
   247→    // Messages buffered while we wait for the Exotel `start` event.
   248→    // Both 'connected' and 'start' are buffered and replayed to the chosen
   249→    // handler so it sees the full Exotel event sequence.
   250→    const buffered: Array<{ data: Buffer; isBinary: boolean }> = [];
   251→    let decided = false;
   252→
   253→    // ── Helpers ────────────────────────────────────────────────────────────────
   254→
   255→    /** Hand the socket to V1 and replay all buffered messages. */
   256→    const fallbackToV1 = (): void => {
   257→      log(`[V2 ROUTER] Fallback to V1 — campaignId=${campaignId ?? "none"}`, "ws");
   258→      ws.off("message", onMessage);
   259→      handleExotelStream(ws, campaignId);
   260→      // Replay buffered messages after V1 registers its own listener.
   261→      for (let i = 0; i < buffered.length; i++) {
   262→        const msg = buffered[i];
   263→        process.nextTick(() => ws.emit("message", msg.data, msg.isBinary));
   264→      }
   265→    };
   266→
   267→    /** Hand the socket to V2 TransportGateway and replay buffered messages. */
   268→    const routeToV2 = (ctx: SessionContext): void => {
   269→      if (!ctx.mediaSession) {
   270→        log(`[V2 ROUTER] Session ${ctx.sessionId} has no MediaSession yet — fallback to V1`, "ws");
   271→        fallbackToV1();
   272→        return;
   273→      }
   274→
   275→      log(`[V2 ROUTER] Routing to V2 — sessionId=${ctx.sessionId} campaignId=${ctx.campaignId}`, "ws");
   276→      ws.off("message", onMessage);
   277→
   278→      try {
   279→        ctx.transportGateway.accept(
   280→          ws as any,          // ITransportGateway uses WsWebSocket (same underlying type)
   281→          ctx.sessionId,
   282→          ctx.callSid ?? "",
   283→          ctx.campaignId,
   284→          "exotel",
   285→          ctx.mediaSession,   // non-null confirmed above
   286→          clientIp
   287→        );
   288→        log(`[V2 ROUTER] Socket owned by TransportGateway — sessionId=${ctx.sessionId}`, "ws");
   289→
   290→        // ── Activate the V2 pipeline ──────────────────────────────────────────
   291→        // Opens a real OpenAI Realtime session, assembles RuntimeIntegration,
   292→        // starts the audio pipeline, and attaches TurnDiagnosticsCollector.
   293→        // Cleanup (disconnect + JSON summary) fires automatically on transport close.
   294→        void activateV2Session(ctx).catch((err: Error) => {
   295→          log(`[V2 ROUTER] activateV2Session failed — sessionId=${ctx.sessionId} err=${err.message}`, "ws");
   296→        });
   297→
   298→        for (let i = 0; i < buffered.length; i++) {
   299→          const msg = buffered[i];
   300→          process.nextTick(() => ws.emit("message", msg.data, msg.isBinary));
   301→        }
   302→      } catch (err: any) {
   303→        log(`[V2 ROUTER] TransportGateway.accept() failed (${err.message}) — fallback to V1`, "ws");
   304→        handleExotelStream(ws, campaignId);
   305→        for (let i = 0; i < buffered.length; i++) {
   306→          const msg = buffered[i];
   307→          process.nextTick(() => ws.emit("message", msg.data, msg.isBinary));
   308→        }
   309→      }
   310→    };
   311→
   312→    // ── Routing listener ───────────────────────────────────────────────────────
   313→
   314→    const onMessage = (data: Buffer, isBinary: boolean): void => {
   315→      if (decided) return;
   316→
   317→      buffered.push({ data, isBinary });
   318→
   319→      const raw = data.toString();
   320→
   321→      let parsed: Record<string, any>;
   322→      try {
   323→        parsed = JSON.parse(raw);
   324→      } catch {
   325→        // Unparseable frame — can't determine event type; fall back to V1.
   326→        decided = true;
   327→        log(`[V2 ROUTER] Unparseable message — fallback to V1`, "ws");
   328→        fallbackToV1();
   329→        return;
   330→      }
   331→
   332→      const event: string = parsed.event ?? "";
   333→
   334→      if (event === "connected") {
   335→        // Exotel sends 'connected' first; wait for 'start' to get callSid.
   336→        log(`[V2 ROUTER] 'connected' received — waiting for 'start'`, "ws");
   337→        return; // keep listener active, continue buffering
   338→      }
   339→
   340→      if (event === "start") {
   341→        decided = true;
   342→
   343→        // Exotel embeds call identifiers inside start.customParameters and
   344→        // the top-level start object depending on the API version.
   345→        const startBlock = parsed.start ?? {};
   346→        const callSid: string =
   347→          startBlock.callSid    ||
   348→          startBlock.callSID    ||
   349→          parsed.callSid        ||
   350→          "";
   351→        const phone: string =
   352→          startBlock.from                             ||
   353→          startBlock.customParameters?.phone          ||
   354→          startBlock.customParameters?.From           ||
   355→          startBlock.customParameters?.callerPhone    ||
   356→          "";
   357→
   358→        log(`[V2 ROUTER] 'start' received — callSid=${callSid || "(none)"} phone=${phone || "(none)"}`, "ws");
   359→
   360→        const coordinator = getV2Coordinator();
   361→        let v2Session: ReturnType<typeof coordinator.getSession> = null;
   362→
   363→        if (callSid) {
   364→          v2Session = coordinator.getSession({ callSid });
   365→          if (v2Session) {
   366→            log(`[V2 ROUTER] Session found by callSid=${callSid}`, "ws");
   367→          }
   368→        }
   369→        if (!v2Session && phone) {
   370→          v2Session = coordinator.getSession({ phone });
   371→          if (v2Session) {
   372→            log(`[V2 ROUTER] Session found by phone=${phone}`, "ws");
   373→          }
   374→        }
   375→
   376→        if (v2Session) {
   377→          routeToV2(v2Session as SessionContext);
   378→        } else {
   379→          log(`[V2 ROUTER] Session missing (callSid=${callSid || "(none)"}, phone=${phone || "(none)"}) — fallback to V1`, "ws");
   380→          fallbackToV1();
   381→        }
   382→        return;
   383→      }
   384→
   385→      // Any unrecognised event before 'start' — safe to fall back to V1.
   386→      decided = true;
   387→      log(`[V2 ROUTER] Unrecognised event '${event}' before 'start' — fallback to V1`, "ws");
   388→      fallbackToV1();
   389→    };
   390→
   391→    ws.on("message", onMessage);
   392→
   393→    ws.on("close", (code) => {
   394→      if (!decided) {
   395→        log(`[V2 ROUTER] Connection closed before routing decision — code=${code}`, "ws");
   396→      }
   397→    });
   398→  });
