   400→  // Single upgrade router — routes by pathname, passes unknown paths through
   401→  httpServer.on("upgrade", (req, socket, head) => {
   402→    let pathname = "/";
   403→    try {
   404→      pathname = new URL(req.url ?? "", `ws://${req.headers.host}`).pathname;
   405→    } catch { /* ignore */ }
   406→
   407→    const clientIp = (req.socket as any)?.remoteAddress ?? "unknown";
   408→    log(`[upgrade] path=${pathname} from=${clientIp} origin=${req.headers.origin ?? "none"} host=${req.headers.host ?? "none"}`, "ws");
   409→
   410→    if (pathname === "/stream") {
   411→      streamWss.handleUpgrade(req, socket as any, head, (ws) => {
   412→        streamWss.emit("connection", ws, req);
   413→      });
   414→    } else if (pathname === "/exotel-stream") {
   415→      log(`[upgrade] routing /exotel-stream to exotel handler`, "ws");
   416→      exotelWss.handleUpgrade(req, socket as any, head, (ws) => {
   417→        exotelWss.emit("connection", ws, req);
   418→      });
   419→    } else {
   420→      log(`[upgrade] unhandled path ${pathname} — leaving for other listeners`, "ws");
   421→    }
   422→
   423→    // Socket error handler to catch rejected handshakes
   424→    socket.on("error", (err) => {
   425→      log(`[upgrade] socket error on ${pathname}: ${err.message}`, "ws");
   426→    });
   427→  });
   428→
   429→  log("WebSocket server ready on path /stream", "ws");
   430→  log("Exotel voicebot stream ready on path /exotel-stream", "ws");
   431→}
