   175→
   176→  /**
   177→   * Starts all components in dependency order.
   178→   *
   179→   * Start order (each step awaited before the next):
   180→   * 1. AudioEngine.start()
   181→   * 2. RealtimeBridge.connect()
   182→   * 3. MediaSession.initialize()
   183→   * 4. MediaSession.start()
   184→   * 5. InboundAudioFlow.start()
   185→   * 6. OutboundAudioFlow.start()
   186→   * 7. SessionSupervisor.start()
   187→   */
   188→  async start(): Promise<void> {
   189→    this._assertState(IntegrationState.IDLE, 'start');
   190→    this._state = IntegrationState.STARTING;
   191→
   192→    this._logger.info('RuntimeIntegration starting');
   193→
   194→    try {
   195→      // Step 1 — Audio engine must be running before any pipeline operations.
   196→      this._audioEngine.start();
   197→      this._logger.debug('RuntimeIntegration: AudioEngine started');
