   260→    this._supervisor.stop();
   261→    this._inboundFlow.stop();
   262→    this._outboundFlow.stop();
   263→
   264→    // Step 4 — Gracefully complete the media session.
   265→    try {
   266→      await this._mediaSession.complete(reason);
   267→    } catch (err) {
   268→      this._logger.warn('RuntimeIntegration: mediaSession.complete() failed during stop', {
   269→        error: String(err),
   270→      });
   271→    }
   272→
   273→    // Step 5 — Close the provider connection.
   274→    try {
   275→      await this._bridge.disconnect();
   276→    } catch (err) {
   277→      this._logger.warn('RuntimeIntegration: bridge.disconnect() failed during stop', {
   278→        error: String(err),
   279→      });
   280→    }
   281→
   282→    // Step 6 — Signal end-of-stream on the audio pipelines.
   283→    this._audioEngine.stop();
   284→
   285→    this._state = IntegrationState.STOPPED;
   286→    this._logger.info('RuntimeIntegration stopped');
   287→  }
