   289→  /**
   290→   * Forcibly tears down all components without waiting for graceful flushing.
   291→   * Idempotent — safe to call from any state or multiple times.
   292→   */
   293→  shutdown(): void {
   294→    if (this._state === IntegrationState.STOPPED) return;
   295→
   296→    this._state = IntegrationState.STOPPING;
   297→    this._logger.warn('RuntimeIntegration shutdown (forced)');
   298→
   299→    // All synchronous teardown paths — no awaiting.
   300→    try { this._supervisor.stop(); } catch { /* swallow */ }
   301→    try { this._inboundFlow.stop(); } catch { /* swallow */ }
   302→    try { this._outboundFlow.stop(); } catch { /* swallow */ }
   303→    try { this._mediaSession.destroy(); } catch { /* swallow */ }
   304→    try { this._bridge.disconnect().catch(() => undefined); } catch { /* swallow */ }
   305→    try { this._audioEngine.destroy(); } catch { /* swallow */ }
   306→
   307→    this._state = IntegrationState.STOPPED;
   308→    this._logger.info('RuntimeIntegration shutdown complete');
   309→  }
