    42→  const prefix = Object.keys(bindings).length
    43→    ? ` ${JSON.stringify(bindings)}`
    44→    : '';
    45→
    46→  const fmt = (level: string, message: string, ctx?: LogContext): string => {
    47→    const ctxStr = ctx && Object.keys(ctx).length ? ` ${JSON.stringify(ctx)}` : '';
    48→    return `[V2Migration${prefix}] [${level.toUpperCase()}] ${message}${ctxStr}`;
    49→  };
    50→
    51→  return {
    52→    debug: (message, ctx) => console.debug(fmt('debug', message, ctx)),
    53→    info:  (message, ctx) => console.info(fmt('info',  message, ctx)),
    54→    warn:  (message, ctx) => console.warn(fmt('warn',  message, ctx)),
    55→    error: (message, ctx) => console.error(fmt('error', message, ctx)),
    56→    child: (childBindings) =>
