   125→/**
   126→ * Returns the process-level `IV2SessionCoordinator` singleton.
   127→ *
   128→ * Lazy-initialises on first call. Thread-safe in Node.js single-threaded
   129→ * runtime — no race condition is possible.
   130→ *
   131→ * On first call this function:
   132→ * 1. Reads `OPENAI_API_KEY` from `process.env`.
   133→ * 2. Logs `[VoiceEngine] OpenAI API Key Present = YES / NO` exactly once.
   134→ * 3. Creates an `OpenAIRealtimeProvider` and wraps `VoiceEngineFactory` with
   135→ *    `ProviderAwareVoiceEngineFactory` so every session automatically gets the
   136→ *    LLM provider injected into its DI container.
   137→ *
   138→ * @returns The singleton coordinator.
   139→ */
   140→export function getV2Coordinator(): IV2SessionCoordinator {
   141→  if (_coordinator) return _coordinator;
   142→
   143→  const logger = createConsoleLogger({ subsystem: 'V2SessionCoordinator' });
   144→
   145→  logger.info('Initialising V2SessionCoordinator singleton');
   146→
   147→  // ── Step 1: resolve the OpenAI API key ──────────────────────────────────────
   148→  const openAIApiKey = process.env.OPENAI_API_KEY ?? '';
   149→
   150→  // Log key presence exactly once (singleton, so this block runs once).
   151→  logger.info(`[VoiceEngine] OpenAI API Key Present = ${openAIApiKey ? 'YES' : 'NO'}`);
   152→
   153→  // ── Step 2: build the engine factory, injecting provider if key is available ─
   154→  let voiceEngineFactory: IVoiceEngineFactory = new VoiceEngineFactory();
   155→
   156→  if (openAIApiKey) {
   157→    try {
   158→      const openAIProvider = createOpenAIRealtimeProvider(
   159→        { apiKey: openAIApiKey },
   160→        logger,
   161→        _noopMetrics
   162→      );
   163→
   164→      voiceEngineFactory = new ProviderAwareVoiceEngineFactory(
   165→        voiceEngineFactory,
   166→        { llm: openAIProvider }
   167→      );
   168→
   169→      logger.info('[VoiceEngine] OpenAI LLM provider registered in DI chain');
   170→    } catch (err: unknown) {
   171→      const message = err instanceof Error ? err.message : String(err);
   172→      logger.warn('[VoiceEngine] Failed to create OpenAI provider — calls will proceed without LLM injection', {
   173→        error: message,
   174→      });
   175→    }
   176→  } else {
   177→    logger.warn('[VoiceEngine] OPENAI_API_KEY not set — LLM provider will NOT be injected into session DI containers');
   178→  }
   179→
   180→  // ── Step 3: assemble the coordinator ────────────────────────────────────────
   181→  _coordinator = createV2SessionCoordinator(
   182→    {
   183→      voiceEngineFactory,
   184→      transportFactory: new TransportFactory(logger),
   185→      logger,
   186→    },
   187→    {
   188→      coordinator: {
   189→        maxSessionAgeMs: 2 * 60 * 60 * 1000, // 2 hours
   190→      },
   191→    }
   192→  );
   193→
   194→  logger.info('V2SessionCoordinator ready', {
   195→    activeSessions: _coordinator.activeSessionCount,
   196→  });
   197→
   198→  return _coordinator;
   199→}
   200→
   201→/**
   202→ * Destroys all active V2 sessions and releases the singleton.
   203→ *
   204→ * Call during process shutdown (SIGTERM / SIGINT) to ensure no sessions
   205→ * are leaked. After this call, the next `getV2Coordinator()` will
   206→ * reinitialise a fresh coordinator.
   207→ */
   208→export function destroyV2Coordinator(): void {
   209→  if (!_coordinator) return;
   210→
   211→  const logger = createConsoleLogger({ subsystem: 'V2SessionCoordinator' });
   212→  const active = _coordinator.activeSessionCount;
   213→
   214→  logger.info('Destroying V2SessionCoordinator', { activeSessions: active });
   215→
