   103→export class InboundAudioFlow implements IInboundAudioFlow {
   104→  private readonly _transport: ITransportGateway;
   105→  private readonly _mediaSession: IMediaSession;
   106→  private readonly _audioEngine: IAudioEngine;
   107→  private readonly _bridge: IRealtimeBridge;
   108→  private readonly _logger: ILogger;
   109→  private readonly _sessionId: string;
   110→  private readonly _config: Readonly<InboundAudioFlowConfig>;
   111→
   112→  private _active = false;
   113→  private _chunkSequence = 0;
   114→
   115→  /**
   116→   * Bound handler reference retained so it can be passed to `off()` exactly.
   117→   */
   118→  private readonly _onAudioReceived: (event: TransportAudioReceivedEvent) => void;
   119→
   120→  constructor(deps: Readonly<InboundAudioFlowDependencies>) {
   121→    this._transport = deps.transport;
   122→    this._mediaSession = deps.mediaSession;
   123→    this._audioEngine = deps.audioEngine;
   124→    this._bridge = deps.bridge;
   125→    this._logger = deps.logger.child({ component: 'InboundAudioFlow', sessionId: deps.sessionId });
   126→    this._sessionId = deps.sessionId;
   127→    this._config = Object.freeze({ ...DEFAULT_INBOUND_CONFIG, ...deps.config });
   128→
   129→    // Pre-bind to allow clean `off()` reference equality.
   130→    this._onAudioReceived = this._handleAudioReceived.bind(this);
   131→  }
   132→
   133→  // ─── Lifecycle ────────────────────────────────────────────────────────────────
   134→
   135→  /**
   136→   * Attaches the inbound audio listener to the transport gateway.
   137→   */
   138→  start(): void {
   139→    if (this._active) return;
   140→    this._active = true;
   141→    this._transport.on('transport.audio_received', this._onAudioReceived);
   142→    this._logger.info('InboundAudioFlow started');
   143→  }
   144→
   145→  /**
   146→   * Detaches the inbound audio listener from the transport gateway.
   147→   */
   148→  stop(): void {
   149→    if (!this._active) return;
   150→    this._active = false;
   151→    this._transport.off('transport.audio_received', this._onAudioReceived);
   152→    this._logger.info('InboundAudioFlow stopped');
   153→  }
   154→
   155→  // ─── Private: Hot Path ───────────────────────────────────────────────────────
   156→
   157→  /**
   158→   * Called for every inbound audio frame received by the transport gateway.
   159→   *
   160→   * Guards:
   161→   * 1. MediaSession must be in the ACTIVE state.
   162→   * 2. AudioEngine must be running.
   163→   * 3. Bridge must be connected.
   164→   *
   165→   * @param event - Decoded transport audio event.
   166→   */
   167→  private _handleAudioReceived(event: TransportAudioReceivedEvent): void {
   168→    // Guard 1 — session state
   169→    if (this._mediaSession.state !== MediaSessionState.ACTIVE) return;
   170→
   171→    // Guard 2 — audio engine
   172→    if (!this._audioEngine.isRunning) return;
   173→
   174→    // Guard 3 — bridge
   175→    if (!this._bridge.isConnected) return;
   176→
   177→    // Build an immutable AudioChunk from the transport event
   178→    const chunk = createAudioChunk({
   179→      sequence: this._chunkSequence++,
   180→      timestamp: event.timestamp,
   181→      sampleRate: event.sampleRate,
   182→      encoding: this._resolveEncoding(event.encoding),
   183→      durationMs: this._estimateDurationMs(event.base64Payload, event.sampleRate),
   184→      payload: event.base64Payload,
   185→      payloadFormat: 'base64',
   186→      direction: 'inbound',
   187→      trackId: event.trackId,
   188→    });
   189→
   190→    // Ingest into the audio engine inbound pipeline
   191→    try {
   192→      this._audioEngine.ingestInbound(chunk);
   193→    } catch (err) {
   194→      this._logger.warn('InboundAudioFlow: audioEngine.ingestInbound failed', {
   195→        error: String(err),
   196→        sequence: chunk.sequence,
   197→      });
   198→      return;
   199→    }
   200→
   201→    // Tick the pipeline to obtain scheduled chunks
   202→    if (!this._config.tickOnIngest) return;
   203→
   204→    const result = this._audioEngine.tickInbound(null);
   205→
   206→    // Forward each scheduled chunk to the AI provider
   207→    for (const scheduled of result.chunksToSend) {
   208→      const base64 = this._toBase64(scheduled.payload);
   209→      if (base64.length > 0) {
   210→        this._bridge.forwardAudio(base64);
   211→      }
   212→    }
   213→  }
   214→
   215→  // ─── Private Helpers ─────────────────────────────────────────────────────────
   216→
   217→  /**
   218→   * Converts a payload to a base64 string.
   219→   * When the payload is already a base64 string, returns it directly.
   220→   * When the payload is a `Uint8Array`, converts via Buffer.
   221→   */
   222→  private _toBase64(payload: Uint8Array | string): string {
   223→    if (typeof payload === 'string') return payload;
   224→    return Buffer.from(payload).toString('base64');
   225→  }
   226→
   227→  /**
   228→   * Resolves the raw encoding string from the transport event to a typed
   229→   * `AudioEncoding`. Falls back to `'mulaw'` for unrecognised encodings.
   230→   */
   231→  private _resolveEncoding(raw: string): 'pcm' | 'pcm16' | 'linear16' | 'mulaw' | 'alaw' | 'opus' {
   232→    const known = new Set(['pcm', 'pcm16', 'linear16', 'mulaw', 'alaw', 'opus']);
   233→    return known.has(raw)
   234→      ? (raw as 'pcm' | 'pcm16' | 'linear16' | 'mulaw' | 'alaw' | 'opus')
   235→      : 'mulaw';
   236→  }
   237→
   238→  /**
   239→   * Estimates the audio duration of a base64-encoded μ-law payload.
   240→   * μ-law: 1 byte per sample at the declared sample rate.
   241→   */
   242→  private _estimateDurationMs(base64Payload: string, sampleRate: number): number {
   243→    if (sampleRate <= 0 || base64Payload.length === 0) return 0;
   244→    const byteLength = Math.floor(base64Payload.length * 0.75);
   245→    return Math.round((byteLength / sampleRate) * 1000);
   246→  }
   247→}
