   114→// ─── Implementation ───────────────────────────────────────────────────────────
   115→
   116→/**
   117→ * Production implementation of `IOutboundAudioFlow`.
   118→ */
   119→export class OutboundAudioFlow implements IOutboundAudioFlow {
   120→  private readonly _bridge: IRealtimeBridge;
   121→  private readonly _audioEngine: IAudioEngine;
   122→  private readonly _transport: ITransportGateway;
   123→  private readonly _sessionId: SessionId;
   124→  private readonly _logger: ILogger;
   125→  private readonly _config: Readonly<OutboundAudioFlowConfig>;
   126→
   127→  private _active = false;
   128→  private _chunkSequence = 0;
   129→
   130→  /**
   131→   * Pre-bound handler references retained for clean `off()` equality.
   132→   */
   133→  private readonly _onAudioReady: (event: BridgeAudioReadyEvent) => void;
   134→  private readonly _onSpeechDetected: (event: BridgeSpeechDetectedEvent) => void;
   135→
   136→  constructor(deps: Readonly<OutboundAudioFlowDependencies>) {
   137→    this._bridge = deps.bridge;
   138→    this._audioEngine = deps.audioEngine;
   139→    this._transport = deps.transport;
   140→    this._sessionId = deps.sessionId;
   141→    this._logger = deps.logger.child({ component: 'OutboundAudioFlow', sessionId: deps.sessionId });
   142→    this._config = Object.freeze({
   143→      ...DEFAULT_OUTBOUND_CONFIG,
   144→      ...deps.config,
   145→      audioFormat: Object.freeze({
   146→        ...DEFAULT_OUTBOUND_CONFIG.audioFormat,
   147→        ...deps.config?.audioFormat,
   148→      }),
   149→    });
   150→
   151→    this._onAudioReady = this._handleAudioReady.bind(this);
   152→    this._onSpeechDetected = this._handleSpeechDetected.bind(this);
   153→  }
   154→
   155→  // ─── Lifecycle ────────────────────────────────────────────────────────────────
   156→
   157→  /**
   158→   * Attaches bridge event listeners and begins outbound audio forwarding.
   159→   */
   160→  start(): void {
   161→    if (this._active) return;
   162→    this._active = true;
   163→    this._bridge.on('bridge.audio_ready', this._onAudioReady);
   164→    this._bridge.on('bridge.speech_detected', this._onSpeechDetected);
   165→    this._logger.info('OutboundAudioFlow started');
   166→  }
   167→
   168→  /**
   169→   * Detaches bridge event listeners and stops outbound audio forwarding.
   170→   */
   171→  stop(): void {
   172→    if (!this._active) return;
   173→    this._active = false;
   174→    this._bridge.off('bridge.audio_ready', this._onAudioReady);
   175→    this._bridge.off('bridge.speech_detected', this._onSpeechDetected);
   176→    this._logger.info('OutboundAudioFlow stopped');
   177→  }
   178→
   179→  // ─── Private: Hot Paths ───────────────────────────────────────────────────────
   180→
   181→  /**
   182→   * Called for every audio delta received from the AI provider.
   183→   * Ingests into the outbound pipeline and delivers scheduled chunks to transport.
   184→   *
   185→   * @param event - Provider audio ready event from the bridge.
   186→   */
   187→  private _handleAudioReady(event: BridgeAudioReadyEvent): void {
   188→    if (!this._audioEngine.isRunning) return;
   189→
   190→    const chunk = this._buildChunk(event.base64Delta, event.timestamp);
   191→
   192→    try {
   193→      this._audioEngine.ingestOutbound(chunk);
   194→    } catch (err) {
   195→      this._logger.warn('OutboundAudioFlow: audioEngine.ingestOutbound failed', {
   196→        error: String(err),
   197→        sequence: chunk.sequence,
   198→      });
   199→      return;
   200→    }
   201→
   202→    if (!this._config.tickOnIngest) return;
   203→
   204→    const result = this._audioEngine.tickOutbound(null);
   205→
   206→    for (const scheduled of result.chunksToSend) {
   207→      this._transport.sendAudio(this._sessionId, scheduled as AudioChunk);
   208→    }
   209→  }
   210→
   211→  /**
   212→   * Called when the provider VAD signals that the caller began speaking
   213→   * (barge-in). Flushes the outbound pipeline and clears the transport buffer
   214→   * to stop audio playback immediately.
   215→   */
   216→  private _handleSpeechDetected(_event: BridgeSpeechDetectedEvent): void {
   217→    if (!this._audioEngine.isRunning) return;
   218→
   219→    this._logger.debug('OutboundAudioFlow: barge-in detected, flushing outbound pipeline');
   220→
   221→    // Flush the engine pipeline (drain any buffered frames)
   222→    const flushResult = this._audioEngine.flushOutbound();
   223→
   224→    // Deliver any remaining frames before clearing
   225→    for (const scheduled of flushResult.chunksToSend) {
   226→      this._transport.sendAudio(this._sessionId, scheduled as AudioChunk);
   227→    }
   228→
   229→    // Clear transport buffer — stops audio playback at the telephony provider
   230→    this._transport.sendClear(this._sessionId);
   231→
   232→    this._logger.debug('OutboundAudioFlow: outbound flushed and transport cleared', {
   233→      flushedChunks: flushResult.chunksToSend.length,
   234→    });
   235→  }
   236→
   237→  // ─── Private Helpers ─────────────────────────────────────────────────────────
   238→
   239→  /**
   240→   * Builds an immutable outbound `AudioChunk` from a provider audio delta.
   241→   *
   242→   * @param base64Delta - Base64-encoded audio from the provider.
   243→   * @param timestamp   - Wall-clock timestamp of the event.
   244→   */
   245→  private _buildChunk(base64Delta: string, timestamp: number): Readonly<AudioChunk> {
   246→    const { sampleRate, encoding } = this._config.audioFormat;
   247→    const byteLength = Math.floor(base64Delta.length * 0.75);
   248→    const durationMs = sampleRate > 0
   249→      ? Math.round((byteLength / sampleRate) * 1000)
   250→      : 0;
   251→
   252→    return createAudioChunk({
   253→      sequence: this._chunkSequence++,
   254→      timestamp,
   255→      sampleRate,
   256→      encoding,
   257→      durationMs,
   258→      payload: base64Delta,
   259→      payloadFormat: 'base64',
   260→      direction: 'outbound',
   261→    });
   262→  }
   263→}
